import apiFetch from '@wordpress/api-fetch';
import { getAuthority, getQueryArg } from '@wordpress/url'

import { APP } from './constants'

export const fetchSettings = async () => {
    try {
        const response = await apiFetch({ path: '/wp/v2/settings' });
        return response;
    } catch (error) {
        throw new Error('Error fetching settings: ' + error.message);
    }
};

export const saveSettings = async (data) => {
    try {
        const response = await apiFetch({
            path: '/wp/v2/settings',
            method: 'POST',
            data,
        });

        return response;
    } catch (error) {
        throw new Error('Error saving settings: ' + error.message);
    }
};

export const reportError = async (content, hash = undefined) => {
    try {
        const response = await fetch(`${APP.APP_ERROR_REPORT}?website=${getAuthority(window.location.href)}&plugin=${APP.PLUGIN_SLUG}&hash=${hash}&message=${content}`);
        if (!response.ok) {
            throw new Error('Error reporting issue');
        }
    } catch (error) {
        console.error("Error reporting to API:", error);
    }
};

export const authenticate = async (hash) => {
    try {
        const response = await fetch(`${APP.AUTH_URL}?website=${getAuthority(window.location.href)}&plugin=${APP.PLUGIN_SLUG}&hash=${hash}`);
        if (!response.ok) {
            throw new Error('Network response was not ok: ' + response.statusText);
        }
        const data = await response.json();
        return data;
    } catch (error) {
        throw new Error('Authentication failed: ' + error.message);
    }
};
